106	pub fn make_pair(a: &FunctionInfo, b: &FunctionInfo, score: f64) -> DuplicatePair {
107	    let (left, right) = order_endpoints(a, b);
108	    DuplicatePair {
109	        score,
110	        left: PairEndpoint {
111	            file: left.file.clone(),
112	            start_line: left.start_line,
113	            end_line: left.end_line,
114	            nodes: left.node_hashes.len(),
115	        },
116	        right: PairEndpoint {
117	            file: right.file.clone(),
118	            start_line: right.start_line,
119	            end_line: right.end_line,
120	            nodes: right.node_hashes.len(),
121	        },
122	    }
123	}
