184	pub fn format_text(pairs: &[DuplicatePair]) -> String {
185	    let mut out = String::new();
186	    for p in pairs {
187	        out.push_str(&format!("DUPLICATE score={:.4}\n", p.score));
188	        out.push_str(&format!(
189	            "  {}:{}-{}\n",
190	            p.left.file, p.left.start_line, p.left.end_line
191	        ));
192	        out.push_str(&format!(
193	            "  {}:{}-{}  ({} nodes / {} nodes)\n",
194	            p.right.file, p.right.start_line, p.right.end_line, p.left.nodes, p.right.nodes
195	        ));
196	    }
197	    out
198	}
