233	fn run_result_to_cli(result: RunResult, format: &OutputFormat) -> CliResult {
234	    match result {
235	        RunResult::Clean => CliResult {
236	            exit_code: 0,
237	            stdout: clean_output(format),
238	            stderr: String::new(),
239	        },
240	        RunResult::Duplicates(pairs) => CliResult {
241	            exit_code: 1,
242	            stdout: format_run_output(format, pairs),
243	            stderr: String::new(),
244	        },
245	        RunResult::Error(msg) => cli_error(msg),
246	    }
247	}
