        assert!(should_skip(std::path::Path::new("src/alpha.rs"), &gs));
        assert!(should_skip(std::path::Path::new("src/beta.rs"), &gs));
        let gs_one = build_glob_set(&["**/alpha.rs".to_string()]).unwrap();
