350	fn collect_subtree_hashes(node: tree_sitter::Node, source: &str, config: &LangConfig) -> Vec<u64> {
351	    let mut hashes = Vec::new();
352	    collect_hashes_recursive(node, source, config, &mut hashes);
353	    hashes.sort_unstable();
354	    hashes
355	}
