357	fn collect_hashes_recursive(
358	    node: tree_sitter::Node,
359	    source: &str,
360	    config: &LangConfig,
361	    hashes: &mut Vec<u64>,
362	) {
363	    let subtree = build_normalized_subtree(node, source, config);
364	    hashes.push(hash_str(&subtree));
365	    let mut cursor = node.walk();
366	    for child in node.children(&mut cursor) {
367	        collect_hashes_recursive(child, source, config, hashes);
368	    }
369	}
