22	    "[a-z][a-z0-9_]{0,8}".prop_map(|s| s)
23	}
24	
25	proptest! {
26	    // --- is_builtin_excluded invariants ---
27	
28	    #[test]
29	    fn builtin_excluded_any_segment_position(
30	        prefix in prop::collection::vec(safe_segment(), 0..3),
31	        excluded in builtin_dir(),
32	        suffix in prop::collection::vec(safe_segment(), 0..3),
33	    ) {
34	        let mut parts = prefix;
35	        parts.push(excluded.to_string());
36	        parts.extend(suffix);
37	        parts.push("file.rs".to_string());
38	        let path = parts.join("/");
